  PROCESSED_SPLIT_GROUP_IDS: 'processed_split_group_ids',
  /** Processed V6 combined transfer IDs for Nostr re-delivery dedup */
  PROCESSED_COMBINED_TRANSFER_IDS: 'processed_combined_transfer_ids',
